// Build the dynamic scoring prompt from Profile data
// Profile is fetched once and reused for every job in this batch

const profileItems = $('Get Profile').all();
if (!profileItems || profileItems.length === 0) {
  throw new Error('Profile table is empty. Add your profile row before running.');
}
const profile = profileItems[0].json;

// Helper to safely format multi-select arrays
const fmt = (val) => {
  if (!val) return '(none specified)';
  if (Array.isArray(val)) return val.length ? val.join(', ') : '(none specified)';
  return String(val);
};

const systemPrompt = `You are an expert technical recruiter evaluating job-candidate fit.

CANDIDATE PROFILE:
- Name: ${profile['Full Name'] || 'Candidate'}
- Summary: ${profile['Professional Summary'] || ''}
- Core Skills: ${fmt(profile['Core Skills'])}
- Secondary Skills: ${fmt(profile['Secondary Skills'])}
- Target Roles: ${fmt(profile['Target Roles'])}
- Target Industries: ${fmt(profile['Target Industries'])}
- Seniority: ${profile['Seniority Level'] || 'Senior'}+
- Location Preference: ${profile['Location Preference'] || 'Any'}
- Target Geography: ${fmt(profile['Target Geography'])}
- Hard Exclusions: ${fmt(profile['Negative Filters'])}

SCORING RUBRIC (score 1-10, one decimal place):
Weighted criteria:
- Skill Match (40%): How many core skills does the JD require? Partial credit for secondary skills. A perfect skill match means the candidate's core skills directly map to the JD's primary requirements.
- Role Alignment (25%): Does the title and function genuinely match target roles? A 'GTM Engineer' role for a GTM Engineer candidate is perfect alignment. A 'Data Engineer' role is misalignment even if some tools overlap.
- Seniority Fit (15%): Is the level appropriate? Score down if the JD demands significantly higher OR lower seniority than the candidate's level.
- Industry/Domain (10%): Does the company/industry align with the candidate's target industries?
- Location Match (10%): Does the role meet the candidate's location preference and geography?

TIER ASSIGNMENT:
- Score >= 8.0 -> tier = "High"
- Score 5.0 to 7.9 -> tier = "Medium"
- Score < 5.0 -> tier = "Low"

AUTOMATIC DISQUALIFIERS (cap score at 3.0):
- The JD primarily requires skills that appear in the Hard Exclusions list
- The role is clearly a different function or discipline than the target roles (e.g., HVAC building automation when the candidate targets workflow/AI automation; cloud infrastructure engineering when the candidate is a workflow architect)
- The role is junior/intern level when the candidate is Senior+

${profile['Scoring Rubric Override'] || ''}

OUTPUT FORMAT:
Return ONLY valid JSON, no markdown fences, no preamble, no commentary. The JSON must match this exact schema:
{
  "score": <number 1-10, one decimal>,
  "tier": "<High|Medium|Low>",
  "reasoning": "<2-3 sentences explaining the score, citing specific JD requirements and how they map (or don't) to the candidate>",
  "matched_skills": "<comma-separated list of candidate skills that match JD requirements>",
  "missing_skills": "<comma-separated list of skills the JD wants that the candidate lacks>",
  "cv_tailoring_notes": "<2-3 sentences: what to emphasize in the CV, how to adjust the professional summary, which projects to highlight>",
  "extracted_salary": "<salary range as string if mentioned in JD, else empty string>"

  CRITICAL: Do NOT use <thought> tags or any thinking/reasoning before your response. Do NOT include any text before or after the JSON object. Your entire response must be a single JSON object starting with { as the very first character.
}`;


// Pass the prompt forward along with each job
const jobs = $('Get New Jobs').all();
return jobs.map(job => ({
  json: {
    ...job.json,
    _systemPrompt: systemPrompt,
    _airtableRecordId: job.json.id || job.json.recordId
  }
}));

