// Parse the AI response and prepare the Airtable update payload

const aiResponse = $input.first().json;

let parsed;
try {
  // With simplified output OFF, content is at choices[0].message.content
  let rawContent;
  if (aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message) {
    rawContent = aiResponse.choices[0].message.content;
  } else if (aiResponse.message && aiResponse.message.content) {
    rawContent = aiResponse.message.content;
  } else if (aiResponse.content) {
    rawContent = aiResponse.content;
  } else if (aiResponse.text) {
    rawContent = aiResponse.text;
  } else {
    rawContent = aiResponse;
  }

  if (typeof rawContent === 'string') {
  // Strip any preamble before the first { (handles thinking tags, markdown fences, etc.)
  const jsonStart = rawContent.indexOf('{');
  if (jsonStart === -1) throw new Error('No JSON object found in AI response');
  rawContent = rawContent.substring(jsonStart);
  // Also strip any trailing content after the last }
  const jsonEnd = rawContent.lastIndexOf('}');
  if (jsonEnd === -1) throw new Error('No closing brace found in AI response');
  rawContent = rawContent.substring(0, jsonEnd + 1);
}
parsed = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (err) {
  throw new Error('Failed to parse AI response as JSON: ' + err.message + ' | Raw: ' + JSON.stringify(aiResponse).slice(0, 500));
}

// Validate required fields
if (typeof parsed.score !== 'number') {
  throw new Error('AI response missing valid score field. Got: ' + JSON.stringify(parsed).slice(0, 300));
}

// Get the original job record from the Loop node
const loopItem = $('Loop Over Jobs').item.json;
const recordId = loopItem._airtableRecordId || loopItem.id;

if (!recordId) {
  throw new Error('Could not find Airtable record ID on the looped job item.');
}

// Cost calculation from actual token usage (when available)
// GPT-5 mini pricing: $0.25/1M input, $2.00/1M output
const INPUT_COST_PER_TOKEN = 0.25 / 1_000_000;
const OUTPUT_COST_PER_TOKEN = 2.00 / 1_000_000;

let estimatedCost = 0; // $0 for local models or missing usage data

const usage = aiResponse.usage 
  || (aiResponse.message && aiResponse.message.usage)
  || null;

if (usage && usage.prompt_tokens && usage.completion_tokens) {
  estimatedCost = (usage.prompt_tokens * INPUT_COST_PER_TOKEN) 
    + (usage.completion_tokens * OUTPUT_COST_PER_TOKEN);
  estimatedCost = Math.round(estimatedCost * 1_000_000) / 1_000_000;
}

return [{
  json: {
    recordId: recordId,
    fields: {
      'Status': 'Evaluated',
      'Fit Score': parsed.score,
      'Fit Tier': parsed.tier,
      'Match Reasoning': parsed.reasoning || '',
      'Matched Skills': parsed.matched_skills || '',
      'Missing Skills': parsed.missing_skills || '',
      'CV Tailoring Notes': parsed.cv_tailoring_notes || '',
      'Salary Info': parsed.extracted_salary || '',
      'AI Evaluation Cost': estimatedCost
    }
  }
}];

// Build interview prep prompt using profile + JD + evaluation results
const profile = $('Get Profile').item.json;
const job = $('Loop Over Jobs').item.json;
const evaluation = $('Parse AI Response').item.json;
const cvMarkdown = profile['CV Markdown'] || '';

const fmt = (val) => {
  if (!val) return '(none specified)';
  if (Array.isArray(val)) return val.length ? val.join(', ') : '(none specified)';
  return String(val);
};

const jsonExample = JSON.stringify({
  "interview_questions": [
    {
      "question": "<likely interview question>",
      "why_asked": "<1 sentence: why the interviewer would ask this based on the JD>",
      "suggested_answer_angle": "<1-2 sentences: how the candidate should approach this given their profile>"
    }
  ],
  "star_responses": [
    {
      "theme": "<skill or competency being tested>",
      "situation": "<brief suggested situation from the candidate's background>",
      "task": "<what the candidate needed to accomplish>",
      "action": "<specific actions to highlight>",
      "result": "<quantifiable outcome to emphasize>"
    }
  ]
}, null, 2);

const interviewPrompt = `You are a senior interview coach preparing a candidate for a specific job interview.

CANDIDATE PROFILE:
- Name: ${profile['Full Name'] || 'Candidate'}
- Professional Summary: ${profile['Professional Summary'] || ''}
- Core Skills: ${fmt(profile['Core Skills'])}
- Secondary Skills: ${fmt(profile['Secondary Skills'])}
- Seniority: ${profile['Seniority Level'] || 'Senior'}

CANDIDATE CV:
${cvMarkdown}

EVALUATION RESULTS:
- Fit Score: ${evaluation.fields['Fit Score']}
- Matched Skills: ${evaluation.fields['Matched Skills']}
- Missing Skills: ${evaluation.fields['Missing Skills']}
- Match Reasoning: ${evaluation.fields['Match Reasoning']}

TARGET JOB:
- Title: ${job['Job Title']}
- Company: ${job.Company}
- Description: ${job['Job Description']}

TASK:
Generate interview preparation material for this specific role. Return ONLY valid JSON, no markdown fences, no preamble. The JSON must match this exact schema:

${jsonExample}

RULES:
- Generate 15 interview questions. Include a mix: 5-6 behavioral, 4-5 technical/situational, 2-3 role-specific, and 2-3 culture/leadership questions.
- Focus questions on the MATCHED SKILLS (these will definitely come up) and MISSING SKILLS (the interviewer will probe gaps).
- Generate 5 STAR responses. Map them to the candidate's actual background — do NOT invent experience.
- For STAR responses, use SPECIFIC projects, roles, and achievements from the candidate's CV — do NOT use generic descriptions. Reference actual company names, tools used, and quantifiable outcomes from the CV.
- Keep everything concise and actionable.

CRITICAL: Do NOT use <thought> tags or any thinking/reasoning before your response. Do NOT include any text before or after the JSON object. Your entire response must be a single JSON object starting with { as the very first character.`;

return [{
  json: {
    _interviewPrompt: interviewPrompt,
    _recordId: evaluation.recordId
  }
}];

// Parse the interview prep AI response and update the Pipeline record

const aiResponse = $input.first().json;
const recordId = $('Build Interview Prep Prompt').item.json._recordId;

// Cost calculation — GPT-5 mini pricing: $0.25/1M input, $2.00/1M output
const INPUT_COST_PER_TOKEN = 0.25 / 1_000_000;
const OUTPUT_COST_PER_TOKEN = 2.00 / 1_000_000;

let interviewPrepCost = 0;

const usage = aiResponse.usage
  || (aiResponse.message && aiResponse.message.usage)
  || null;

if (usage && usage.prompt_tokens && usage.completion_tokens) {
  interviewPrepCost = (usage.prompt_tokens * INPUT_COST_PER_TOKEN)
    + (usage.completion_tokens * OUTPUT_COST_PER_TOKEN);
  interviewPrepCost = Math.round(interviewPrepCost * 1_000_000) / 1_000_000;
}

let parsed;
try {
  let rawContent;
  if (aiResponse.choices && aiResponse.choices[0] && aiResponse.choices[0].message) {
    rawContent = aiResponse.choices[0].message.content;
  } else if (aiResponse.message && aiResponse.message.content) {
    rawContent = aiResponse.message.content;
  } else if (aiResponse.content) {
    rawContent = aiResponse.content;
  } else if (aiResponse.text) {
    rawContent = aiResponse.text;
  } else {
    rawContent = aiResponse;
  }
  if (typeof rawContent === 'string') {
  const jsonStart = rawContent.indexOf('{');
  if (jsonStart === -1) throw new Error('No JSON object found in AI response');
  rawContent = rawContent.substring(jsonStart);
  const jsonEnd = rawContent.lastIndexOf('}');
  if (jsonEnd === -1) throw new Error('No closing brace found in AI response');
  rawContent = rawContent.substring(0, jsonEnd + 1);
}
parsed = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (err) {
  return [{
    json: {
      recordId: recordId,
      interviewQuestions: '(Interview prep generation failed: ' + err.message + ')',
      starResponses: '',
      interviewPrepCost: interviewPrepCost
    }
  }];
}

// Format interview questions as readable text
let questionsText = '';
if (parsed.interview_questions && Array.isArray(parsed.interview_questions)) {
  questionsText = parsed.interview_questions.map((q, i) => {
    return `${i + 1}. ${q.question}\n   Why asked: ${q.why_asked}\n   Approach: ${q.suggested_answer_angle}`;
  }).join('\n\n');
}

// Format STAR responses as readable text
let starText = '';
if (parsed.star_responses && Array.isArray(parsed.star_responses)) {
  starText = parsed.star_responses.map((s, i) => {
    return `${i + 1}. Theme: ${s.theme}\n   Situation: ${s.situation}\n   Task: ${s.task}\n   Action: ${s.action}\n   Result: ${s.result}`;
  }).join('\n\n');
}

return [{
  json: {
    recordId: recordId,
    interviewQuestions: questionsText,
    starResponses: starText,
    interviewPrepCost: interviewPrepCost
  }
}];
